import CartView from "../Components/CartView/CartView";
import { Navigate } from "react-router-dom";


export default function CartPage() {
    
    return (
        <CartView>
            <button
                        onClick={() => navigate('/checkout')}
                        className="btn-primary checkout-btn"
                    >
                        Proceder al Pago
                    </button>
        </CartView>
    )
}
